"use client";

import * as SwitchPrimitive from "@radix-ui/react-switch";
import { animate, motion, useMotionValue, useTransform } from "motion/react";
import { forwardRef, useEffect, useRef, useState } from "react";
import { cn } from "@/lib/utils";

import { MotionConfig, useReducedMotion } from "motion/react";
import { createContext, useContext } from "react";

interface ReducedMotionProp {
  reducedMotion?: boolean;
}

const ReducedMotionOverrideContext = createContext(false);

function useResolvedReducedMotion(reducedMotion?: boolean) {
  const reducedMotionOverride = useContext(ReducedMotionOverrideContext);
  const prefersReducedMotion = useReducedMotion() ?? false;

  return Boolean(
    reducedMotion || reducedMotionOverride || prefersReducedMotion
  );
}

function ReducedMotionConfig({
  children,
  reducedMotion,
}: ReducedMotionProp & {
  children: import("react").ReactNode;
}) {
  const resolvedReducedMotion = useResolvedReducedMotion(reducedMotion);

  return (
    <MotionConfig reducedMotion={resolvedReducedMotion ? "always" : "user"}>
      {children}
    </MotionConfig>
  );
}

const lightTokens = [
  "[--background:#ffffff]",
  "[--foreground:#111111]",
  "[--primary:#111111]",
  "[--secondary:#646b75]",
  "[--surface-border:#e9edf2]",
  "[--border:#e3e7ec]",
  "[--card:#ffffff]",
  "[--card-foreground:#111111]",
  "[--muted:#f5f7fa]",
  "[--muted-foreground:#6d7480]",
  "[--accent:#f3f5f8]",
  "[--accent-foreground:#111111]",
  "[--input:#e3e7ec]",
  "[--ring:rgba(17,17,17,0.16)]",
  "[--destructive:#dc2626]",
  "[--paper:#fcfcfd]",
  "[--popover-foreground:#111111]",
  "[--brand:#0ea5e9]",
  "[--brand-soft:#bae6fd]",
  "[--shadow-soft:0_18px_38px_-24px_rgba(15,23,42,0.35)]",
];

const aliasTokens = [
  "[--color-background:var(--background)]",
  "[--color-foreground:var(--foreground)]",
  "[--color-primary:var(--primary)]",
  "[--color-secondary:var(--secondary)]",
  "[--color-border:var(--border)]",
  "[--color-card:var(--card)]",
  "[--color-card-foreground:var(--card-foreground)]",
  "[--color-muted:var(--muted)]",
  "[--color-muted-foreground:var(--muted-foreground)]",
  "[--color-accent:var(--accent)]",
  "[--color-accent-foreground:var(--accent-foreground)]",
  "[--color-input:var(--input)]",
  "[--color-ring:var(--ring)]",
  "[--color-destructive:var(--destructive)]",
  "[--color-paper:var(--paper)]",
  "[--color-popover-foreground:var(--popover-foreground)]",
  "[--color-brand:var(--brand)]",
  "[--color-brand-soft:var(--brand-soft)]",
];

const darkTokens = [
  "dark:[--background:#111111]",
  "dark:[--foreground:#f6f3ec]",
  "dark:[--primary:#f6f3ec]",
  "dark:[--secondary:#cbc6bb]",
  "dark:[--surface-border:#2a2a25]",
  "dark:[--border:#2b2a25]",
  "dark:[--card:#111111]",
  "dark:[--card-foreground:#f6f3ec]",
  "dark:[--muted:#171716]",
  "dark:[--muted-foreground:#9a958a]",
  "dark:[--accent:#1a1a18]",
  "dark:[--accent-foreground:#f6f3ec]",
  "dark:[--input:#2b2a25]",
  "dark:[--ring:rgba(246,243,236,0.18)]",
  "dark:[--destructive:#f87171]",
  "dark:[--paper:#171716]",
  "dark:[--popover-foreground:#f6f3ec]",
  "dark:[--brand:#38bdf8]",
  "dark:[--brand-soft:#0c4a6e]",
  "dark:[--shadow-soft:0_20px_44px_-28px_rgba(0,0,0,0.6)]",
];

const registryTheme = [
  ...lightTokens,
  ...aliasTokens,
  ...darkTokens,
].join(" ");

const TRACK_W = 44;
const TRACK_H = 26;
const THUMB_SIZE = 20;
const THUMB_TRAVEL = TRACK_W - THUMB_SIZE - 4; // px from left to right (margin 2px each side)

const spring = { type: "spring" as const, duration: 0.35, bounce: 0.3 };
const springFast = { type: "spring" as const, duration: 0.15, bounce: 0 };
const springSnap = { type: "spring" as const, duration: 0.4, bounce: 0.5 };

interface SwitchProps
  extends Omit<
      React.ComponentPropsWithoutRef<typeof SwitchPrimitive.Root>,
      "asChild"
    >,
    ReducedMotionProp {
  label?: string;
  /** @default "right" */
  labelSide?: "left" | "right";
}

const Switch = forwardRef<
  React.ElementRef<typeof SwitchPrimitive.Root>,
  SwitchProps
>(
  (
    {
      checked,
      onCheckedChange,
      label,
      labelSide = "right",
      className,
      disabled,
      defaultChecked,
      reducedMotion,
      ...props
    },
    ref
  ) => {
    const isControlled = checked !== undefined;
    const [uncontrolledChecked, setUncontrolledChecked] = useState(
      Boolean(defaultChecked)
    );
    const internalChecked = isControlled ? checked : uncontrolledChecked;

    const thumbX = useMotionValue(internalChecked ? THUMB_TRAVEL : 0);
    const thumbScaleX = useMotionValue(1);
    const thumbScaleY = useMotionValue(1);

    const fillOpacity = useTransform(thumbX, [0, THUMB_TRAVEL], [0, 1]);
    const reduceMotion = useResolvedReducedMotion(reducedMotion);

    const prevChecked = useRef(internalChecked);
    const directionRef = useRef<1 | -1>(1);

    useEffect(() => {
      if (prevChecked.current === internalChecked) return;
      prevChecked.current = internalChecked;
      if (reduceMotion) {
        thumbX.set(internalChecked ? THUMB_TRAVEL : 0);
        return;
      }

      animate(thumbX, internalChecked ? THUMB_TRAVEL : 0, spring);
    }, [internalChecked, reduceMotion, thumbX]);

    const handlePointerDown = () => {
      if (reduceMotion) {
        return;
      }

      // Flatten thumb on press (squeeze effect)
      animate(thumbScaleX, 0.82, springFast);
      animate(thumbScaleY, 1.1, springFast);
    };

    const handlePointerUp = () => {
      if (reduceMotion) {
        thumbScaleX.set(1);
        thumbScaleY.set(1);
        return;
      }

      // Snap back with bounce
      animate(thumbScaleX, 1, springSnap);
      animate(thumbScaleY, 1, springSnap);
    };

    const handleCheckedChange = (next: boolean) => {
      directionRef.current = next ? 1 : -1;

      if (!isControlled) {
        setUncontrolledChecked(next);
      }

      if (reduceMotion) {
        thumbScaleX.set(1);
        thumbScaleY.set(1);
        thumbX.set(next ? THUMB_TRAVEL : 0);
        onCheckedChange?.(next);
        return;
      }

      // Squeeze in direction of travel on release
      animate(thumbScaleX, 1.15, springFast).then(() => {
        animate(thumbScaleX, 1, springSnap);
      });
      animate(thumbScaleY, 0.88, springFast).then(() => {
        animate(thumbScaleY, 1, springSnap);
      });

      animate(thumbX, next ? THUMB_TRAVEL : 0, spring);
      onCheckedChange?.(next);
    };

    const toggleFromLabel = () => {
      if (disabled) return;
      handleCheckedChange(!internalChecked);
    };

    const switchEl = (
      <SwitchPrimitive.Root
        checked={internalChecked}
        className={cn(
          registryTheme,
          "relative inline-flex shrink-0 cursor-pointer items-center rounded-full",
          "outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background",
          "disabled:cursor-not-allowed disabled:opacity-50",
          className
        )}
        disabled={disabled}
        onCheckedChange={handleCheckedChange}
        onPointerDown={handlePointerDown}
        onPointerLeave={handlePointerUp}
        onPointerUp={handlePointerUp}
        ref={ref}
        style={{ width: TRACK_W, height: TRACK_H }}
        {...props}
      >
        <span
          className="absolute inset-0 rounded-full"
          style={{ backgroundColor: "var(--accent)" }}
        />

        <motion.span
          className="absolute inset-0 rounded-full"
          style={{
            backgroundColor: "var(--foreground)",
            opacity: fillOpacity,
          }}
        />

        <SwitchPrimitive.Thumb asChild>
          <motion.span
            className="pointer-events-none z-10 block rounded-full"
            style={{
              width: THUMB_SIZE,
              height: THUMB_SIZE,
              x: thumbX,
              scaleX: thumbScaleX,
              scaleY: thumbScaleY,
              marginLeft: 2,
              backgroundColor: "white",
              boxShadow:
                "0 1px 4px rgba(0,0,0,0.18), 0 0 0 1px rgba(0,0,0,0.06)",
            }}
          />
        </SwitchPrimitive.Thumb>
      </SwitchPrimitive.Root>
    );

    if (!label) {
      return (
        <ReducedMotionConfig reducedMotion={reducedMotion}>
          {switchEl}
        </ReducedMotionConfig>
      );
    }

    return (
      <ReducedMotionConfig reducedMotion={reducedMotion}>
        <div
          className={cn(
            registryTheme,
            "flex cursor-pointer select-none items-center gap-2.5",
            disabled && "cursor-not-allowed opacity-50"
          )}
        >
          {labelSide === "left" && (
            <button
              className="bg-transparent p-0 text-foreground text-sm"
              disabled={disabled}
              onClick={toggleFromLabel}
              type="button"
            >
              {label}
            </button>
          )}
          {switchEl}
          {labelSide === "right" && (
            <button
              className="bg-transparent p-0 text-foreground text-sm"
              disabled={disabled}
              onClick={toggleFromLabel}
              type="button"
            >
              {label}
            </button>
          )}
        </div>
      </ReducedMotionConfig>
    );
  }
);

Switch.displayName = "Switch";

export { Switch, type SwitchProps };
